INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00763', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '1992年「地球高峰會議」之後，迄今已有一百多個國家先後簽署了「生物多樣性公約」，並積極展開生物 多樣性工作。關於此重要議題，下列敘述何者錯誤？', '["我國為該公約的締約國，對國內的生物資源擁有主權，並負有保育責任", "生物多樣性的內涵，可以分為遺傳多樣性、物種多樣性和生態系多樣性", "成立生物多樣性資訊交換中心，有助於本土生物多樣性資料的蒐集與分享", "國家公園的建立，可以就地保育生物的棲息環境，讓它們自然生長與繁衍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00764', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '一國面對景氣衰退時，政府往往會透過一些措施刺激景氣復甦，帶動經濟成長。下列何者較無法達成刺激 景氣復甦的目標？', '["增加公共投資", "降低重貼現率", "獎勵民間投資", "引導本國幣匯率升值"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00765', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '在實際市場交易過程中，買賣雙方所擁有的資訊常出現不對稱情形，下列何者不是為了解決資訊不對稱所 採行的措施？', '["內政部要求售屋房價實價登錄", "市場禁宰活禽以防堵禽流感擴散", "臺東池上米推出產地標章認證", "保險業者承保前要求客戶健康檢查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00766', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '民意調查是運用系統性、科學性的方法，對民意進行蒐集、研究與分析的一種專業行為。關於民意調查的 敘述，下列何者正確？', '["可以用來了解民眾對政府施政的滿意程度，以及監督政府的政策", "由政府所成立的民調中心，比民營的民調中心更具有信度與效度", "利用網路實施民調，因抽取樣本較為方便，故較能反應真實民意", "民調結果呈現雙峰型曲線，表示民眾對此議題持中性看法者居多"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00767', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '夏、秋兩季常有颱風侵襲臺灣，因而造成龐大的農業損失。特別是颱風前後葉菜類的蔬菜等農產品的價格 的大幅上漲，連帶也造成根莖類農產的價格上漲，造成消費者叫苦連天。下列關於颱風後菜價上揚原因的 敘述，何者錯誤？', '["蔬菜對消費者而言屬於正常財", "消費者預期未來價格上漲", "根莖類作物為葉菜類的替代品", "葉菜類受災損造成供給減少"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00768', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '自 1997 年京都議定書訂定以降，氣候變遷成為全球各國關注的議題，其後經歷 2009 年哥本哈根會議、 2011年南非德班會議及2015年巴黎協定。下列何者不是上述會議協議中，各國對環境變遷所做出之共識？', '["相較於前工業化時代的溫度，全球平均溫度上升保持在攝氏2度內", "已開發國家應協助開發中國家建立替代能源及技術", "各國達成對違反減排氣體國家之懲罰金共識", "訂定可交易排放許可證制度以建立污染權交易機制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00769', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '某對夫妻皆為銀行之職員，兩人結婚後太太順利懷胎生子後，其中一人選擇辭去工作在家照顧小孩，另一 人則繼續在銀行工作。若其他條件不變，其中一人辭職對勞動市場影響之敘述，下列何者正確？', '["勞動參與率下降", "勞動參與率不變", "失業率不變", "失業率下降"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00770', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '地球環境不斷惡化，為了我們及後代子孫的未來，永續發展已成為人類必須追求的重要目標。下列何者並 非永續發展的概念？', '["應只有已開發國家負責解決目前的污染問題", "國家發展經濟時必須考慮環境的承載能力", "維護生物的多樣化屬於永續發展的環境面", "無論當代或下一代的人們皆須追求環境保護"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00771', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '某合成石材生產廠商將未經處理的工業廢水排入河流中，經民眾舉發後，政府要求該廠商限期改善並處以 罰鍰。下列敘述何者正確？', '["石材產品的需求曲線朝左移動", "民眾對該石材產品的市場需求量將增加", "該石材產品的市場供給曲線將向左移動", "因為河流是屬於純公共財，才會造成污染情況不斷發生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00772', 'judicial-57f41407', 'judicial-57f41407-moex-110-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '下列何者較無助於提升經濟成長？', '["政府規劃科學園區", "提高環保標準減少污染", "企業與學校之間的產學合作", "部分大學擠進世界大學排行的前百大"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "08d4f4894bda", "answer_pdf_sha1": "46c7c4f93357", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "301", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
